ParentArray add(int ordinal, int parentOrdinal) {
    if (ordinal >= parentOrdinals.length) {
      int[] newarray = ArrayUtil.grow(parentOrdinals);
      newarray[ordinal] = parentOrdinal;
      return new ParentArray(newarray);
    }
